    queue<int> q1, q2;
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        if (op == "push") {
            int x;
            cin >> x;
            q2.push(x);
            while (!q1.empty()) {
                q2.push(q1.front());
                q1.pop();
            }
            swap(q1, q2);
        } else if (op == "pop") {
            if (!q1.empty()) {
                q1.pop();
            } else {
                cout << "Invalid Operation" << endl;
            }
        } else if (op == "top") {
            if (!q1.empty()) {
                cout << q1.front() << endl;
            } else {
                cout << "Invalid Operation" << endl;
            }
        }
    }
